interface ProjectInfo {
  name: string
  path: string
  genre: string
  status: string
  lastModified: string
}

interface ProjectManagerProps {
  visible: boolean
  mode?: 'create' | 'list'
  onClose: () => void
  onProjectOpened: (projectPath: string) => void
}

// 默认项目结构
